+    "library": "window.sheets = {
  getCurrentCell: function() {
    const nameBox = document.querySelector('#t-name-box');
    return nameBox?.value || null;
  },

  getCurrentCellValue: async function() {
    const formulaBar = document.querySelector('#t-formula-bar-input');
    return formulaBar?.textContent || '';
  },

  navigateToCell: async function(cellAddress) {
    const match = cellAddress.match(/^([A-Z]+)(\d+)$/);
    if (!match) throw new Error('Invalid cell address: ' + cellAddress);
    const nameBox = document.querySelector('#t-name-box');
    if (nameBox) {
      nameBox.value = cellAddress;
      nameBox.dispatchEvent(new Event('input', { bubbles: true }));
      nameBox.focus();
    }
    await nativePress('Enter');
  },

  selectRange: async function(range) {
    const nameBox = document.querySelector('#t-name-box');
    if (nameBox) {
      nameBox.value = range;
      nameBox.dispatchEvent(new Event('input', { bubbles: true }));
      nameBox.focus();
    }
    await nativePress('Enter');
    await new Promise(r => setTimeout(r, 1000));
  },

  setCellValue: async function(cellAddress, value) {
    await this.navigateToCell(cellAddress);
    await nativePress('Backspace');
    await nativeType('#t-formula-bar-input', String(value));
    await nativePress('Tab');
  },

  getCellValue: async function(cellAddress) {
    const startCell = this.getCurrentCell();
    await this.navigateToCell(cellAddress);
    const value = await this.getCurrentCellValue();
    if (startCell && startCell !== cellAddress) {
      await this.navigateToCell(startCell);
    }
    return value;
  },

  setTitle: async function(title) {
    const titleInput = document.querySelector('input[aria-label="Rename"]');
    if (titleInput) {
      titleInput.value = title;
      titleInput.dispatchEvent(new Event('input', { bubbles: true }));
      titleInput.dispatchEvent(new Event('change', { bubbles: true }));
      titleInput.focus();
      await nativePress('Enter');
      await nativeClick('#waffle-grid-container');
    }
  },

  clearAll: async function() {
    await nativeKeyDown('Meta');
    await nativeKeyDown('a');
    await nativeKeyUp('a');
    await nativeKeyUp('Meta');
    await nativePress('Backspace');
  },

  getAvailableColors: async function() {
    const cellColorBtn = document.querySelector('#t-cell-color');
    if (cellColorBtn && cellColorBtn.getBoundingClientRect().width === 0) {
      await nativeClick('#moreButton');
      await new Promise(r => setTimeout(r, 300));
    }
    await nativeClick('#t-cell-color');
    await new Promise(r => setTimeout(r, 500));

    const allSwatches = document.querySelectorAll('.docs-material-colorpalette-colorswatch');
    const visibleSwatches = Array.from(allSwatches).filter(s => {
      const rect = s.getBoundingClientRect();
      return rect.width > 0 && rect.height > 0;
    });

    const colors = visibleSwatches.map((swatch, index) => ({
