  setRange: async function(range, values) {
    const match = range.match(/^([A-Z]+)(\d+):([A-Z]+)(\d+)$/);
    if (!match) throw new Error('Invalid range format: ' + range);

    const startCol = this._colToNum(match[1]);
    const startRow = parseInt(match[2]);
    const endCol = this._colToNum(match[3]);
    const endRow = parseInt(match[4]);

    const expectedRows = endRow - startRow + 1;
    const expectedCols = endCol - startCol + 1;
    if (values.length !== expectedRows) {
      throw new Error(`Expected ${expectedRows} rows, got ${values.length}`);
    }

    let rowIdx = 0;
    for (let row = startRow; row <= endRow; row++) {
      const rowData = values[rowIdx];
      if (rowData.length !== expectedCols) {
        throw new Error(`Row ${rowIdx} expected ${expectedCols} columns, got ${rowData.length}`);
      }

      let colIdx = 0;
      for (let col = startCol; col <= endCol; col++) {
        const cellAddress = this._numToCol(col) + row;
        const value = rowData[colIdx];
        await this.setCellValue(cellAddress, value);
        colIdx++;
      }
      rowIdx++;
    }
  }
