          if (!hasYourReply) {
            unanswered.push({
              ...comment,
              parentComment: parentComment
            });
          }
        }

        if (comment.replies.length > 0) {
          traverse(comment.replies, comment);
        }
      });
    }

    traverse(commentTree);
